      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  if (!f.getItemValue('tu_nam')) f.getItem('tu_nam').value = (new Date()).getFullYear();
  if (!f.getItemValue('den_nam')) f.getItem('den_nam').value = (new Date()).getFullYear();
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      g._hiddenFields = [{Fields: 'gt_kh_ky_nt', Value: (f.getItemValue('mau_bc')) == '10'}];
      var p1 = f.getItem('tu_ky').value, p2 = f.getItem('den_ky').value, y1 = f.getItem('tu_nam').value, y2 = f.getItem('den_nam').value;
      g._p1 = f.getItemValue('tu_ky');
      g._p2 = f.getItemValue('den_ky');
      g._y1 = f.getItemValue('tu_nam');
      g._y2 = f.getItemValue('den_nam');
      g._xtype = f.getItemValue('mau_bc');
      g._u = f.getItemValue('ma_dvcs');
      g._alterTitle = [null, [['%p1', p1, true], ['%y1', y1, true], ['%p2', p2, true], ['%y2', y2, true]]];
      remove$GridReport$Filter(g);
      break;
    default:
      break;
  }
}
